      size = spData[idx][i][2];
      length = spData[idx][i][3];
      y *= 0.9;
      size *= 1.4;
      length *= 1.05;
      x = -x;
      y = y;
      deg %= 180;
      if (c == Letter.LINE_COLOR)
        Letter.setBoxLine(x, y, size, length, deg);
      else if (c == Letter.POLY_COLOR)
        Letter.setBoxPoly(x, y, size, length, deg);
