  private static setBoxPart(width: number, height: number): void {
    glVertex3(-width / 2, 0, 0);
    glVertex3(-width / 3 * 1, -height / 2, 0);
    glVertex3( width / 3 * 1, -height / 2, 0);
    glVertex3( width / 2, 0, 0);
    glVertex3( width / 3 * 1,  height / 2, 0);
    glVertex3(-width / 3 * 1,  height / 2, 0);
  }
  
